1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const QUOTE_HIGH_ENCH_THRESHOLD = 5;
5	const QUOTE_HIGH_ENCH_RATE = 0.3;
6	const CLAIM_HIGH_ENCH_THRESHOLD = 8;
7	const CLAIM_HIGH_ENCH_RATE = 0.5;
8	const BLOCK_SIZE = 3;
9	const BLOCK_PREMIUM = 60;
10	const LOYALTY_THRESHOLD = 2;
11	const LOYALTY_RATE = 0.2;
12	const FOLLOWUP_RATE = 0.15;
13	const CAP_MULTIPLIER = 2;
14	const DEDUCTIBLE_PER_DAMAGE = 100;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const INSURANCE_VALUES: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const COMPONENT_TYPES = ["rune", "moonstone"];
35	
36	type Item = { type: string; cursed?: boolean; enchantment?: number };
37	
38	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
40	const isCursed = (item: Item): boolean => item.cursed === true;
41	const isHighlyEnchantedForQuote = (item: Item): boolean =>
42	  enchantmentLevel(item) >= QUOTE_HIGH_ENCH_THRESHOLD;
43	const isHighlyEnchantedForClaim = (item: Item): boolean =>
44	  enchantmentLevel(item) >= CLAIM_HIGH_ENCH_THRESHOLD;
45	
46	const sum = (values: number[]): number =>
47	  values.reduce((total, value) => total + value, 0);
48	
49	const sumOfBasePremiums = (items: Item[]): number =>
50	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
51	
52	const groupByType = (items: Item[]): Item[][] => {
53	  const groups: Record<string, Item[]> = {};
54	  for (const item of items) {
55	    if (!groups[item.type]) groups[item.type] = [];
56	    groups[item.type].push(item);
57	  }
58	  return Object.values(groups);
59	};
60	
61	const basePremiumForComponentGroup = (group: Item[]): number =>
62	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
63	
64	const basePremiumFor = (items: Item[]): number => {
65	  const components = items.filter(isComponent);
66	  const nonComponents = items.filter((item) => !isComponent(item));
67	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
68	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
69	};
70	
71	const surchargeFor = (
72	  items: Item[],
73	  rate: number,
74	  applies: (item: Item) => boolean,
75	): number =>
76	  sum(items.map((item) => (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0)));
77	
78	const quotePremium = (items: Item[], yearsWithMHPCO: number, quoteIndex: number): number => {
79	  const base = basePremiumFor(items);
80	  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
81	  const highEnchSurcharge = surchargeFor(items, QUOTE_HIGH_ENCH_RATE, isHighlyEnchantedForQuote);
82	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? base * LOYALTY_RATE : 0;
83	  const followupDiscount = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
84	  const firstInsuranceFee = base * FIRST_INSURANCE_RATE;
85	  const total = base + curseSurcharge + highEnchSurcharge
86	    - loyaltyDiscount - followupDiscount
87	    + firstInsuranceFee + PROCESSING_FEE;
88	  return Math.ceil(total);
89	};
90	
91	type Policy = { items: Item[]; insuranceSum: number; remainingCap: number };
92	
93	const insuranceSumFor = (items: Item[]): number =>
94	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
95	
96	const reimbursableAmount = (damageAmount: number, item: Item | undefined): number =>
97	  item && isHighlyEnchantedForClaim(item)
98	    ? damageAmount * CLAIM_HIGH_ENCH_RATE
99	    : damageAmount;
100	
101	const handleClaim = (step: any, policies: Record<number, Policy>): { payout: number; remainingCap: number } => {
102	  const policy = policies[step.policy];
103	  const damages = step.incident.damages;
104	  const totalPayout = sum(
105	    damages.map((damage: { itemType: string; amount: number }) => {
106	      const item = policy.items.find((i) => i.type === damage.itemType);
107	      const reimbursable = reimbursableAmount(damage.amount, item);
108	      return Math.max(0, Math.floor(reimbursable - DEDUCTIBLE_PER_DAMAGE));
109	    })
110	  );
111	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
112	  policy.remainingCap -= cappedPayout;
113	  return { payout: cappedPayout, remainingCap: policy.remainingCap };
114	};
115	
116	const validateItemTypes = (items: Item[]): void => {
117	  for (const item of items) {
118	    if (!(item.type in BASE_PREMIUMS)) {
119	      throw new Error(`unknown item type: ${item.type}`);
120	    }
121	  }
122	};
123	
124	export const runScenario = (scenario: any): unknown => {
125	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
126	  let quoteIndex = 0;
127	  const policies: Record<number, Policy> = {};
128	  const results = scenario.steps.map((step: any, stepIndex: number) => {
129	    if (step.op === "claim") {
130	      return handleClaim(step, policies);
131	    }
132	    validateItemTypes(step.items);
133	    const premium = quotePremium(step.items, yearsWithMHPCO, quoteIndex);
134	    const insuranceSum = insuranceSumFor(step.items);
135	    policies[stepIndex] = {
136	      items: step.items,
137	      insuranceSum,
138	      remainingCap: insuranceSum * CAP_MULTIPLIER,
139	    };
140	    quoteIndex++;
141	    return { premium };
142	  });
143	  return { results };
144	};
