const handleClaim = (step: any, policies: Record<number, Policy>): { payout: number; remainingCap: number } => {
  const policy = policies[step.policy];
  const damages = step.incident.damages;
  for (const damage of damages) {
    if (!policy.items.find((i) => i.type === damage.itemType)) {
      throw new Error(`${damage.itemType} not in policy`);
    }
  }
  const totalPayout = sum(
    damages.map((damage: { itemType: string; amount: number }) => {
      const item = policy.items.find((i) => i.type === damage.itemType);
      const reimbursable = reimbursableAmount(damage.amount, item);
      return Math.max(0, Math.floor(reimbursable - DEDUCTIBLE_PER_DAMAGE));
    })
  );
